  1	import * as React from 'react';
  2	import { Button, ButtonVariant, Popover, PopoverPosition } from '@patternfly/react-core';
  3	import { connect } from 'react-redux';
  4	import { bindActionCreators } from 'redux';
  5	import { KialiDispatch } from 'types/Redux';
  6	import { KialiAppState } from 'store/Store';
  7	import ReactResizeDetector from 'react-resize-detector';
  8	import { KialiIcon } from 'config/KialiIcon';
  9	import { TourActions } from 'actions/TourActions';
 10	import { kialiStyle } from 'styles/StyleUtils';
 11	import { PFColors } from 'components/Pf/PfColors';
 12	import { t } from 'utils/I18nUtils';
 13	
 14	export interface TourStopInfo {
 15	  description?: string; // displayed as the tour stop body
 16	  distance?: number; // distance from target, default=25
 17	  htmlDescription?: React.ReactNode;
 18	  isValid?: boolean; // internal use, leave unset
 19	  name: string; // displayed in the tour stop header.
 20	  position?: PopoverPosition;
 21	}
 22	
 23	export interface TourInfo {
 24	  name: string;
 25	  stops: Array<TourStopInfo>;
 26	}
 27	
 28	const stopNumberStyle = kialiStyle({
 29	  borderRadius: '1rem',
 30	  backgroundColor: PFColors.Blue300,
 31	  display: 'inline-block',
 32	  width: '1.5rem',
 33	  textAlign: 'center',
 34	  marginRight: '0.5rem',
 35	  color: PFColors.White
 36	});
 37	
 38	type ReduxStateProps = {
 39	  activeStop?: number;
 40	  activeTour?: TourInfo;
 41	};
 42	
 43	type ReduxDispatchProps = {
 44	  endTour: () => void;
 45	  setStop: (stop: number) => void;
 46	};
 47	
 48	type TourStopProps = ReduxStateProps &
 49	  ReduxDispatchProps & {
 50	    children?: React.ReactNode;
 51	    info: TourStopInfo | TourStopInfo[];
 52	  };
 53	
 54	const buttonsStyle = kialiStyle({
 55	  display: 'flex',
 56	  justifyContent: 'space-between'
 57	});
 58	
 59	export function getNextTourStop(
 60	  activeTour: TourInfo,
 61	  activeStop: number,
 62	  direction: 'back' | 'forward'
 63	): number | undefined {
 64	  if (direction === 'back') {
 65	    for (let i: number = activeStop - 1; i >= 0; --i) {
 66	      if (activeTour.stops[i].isValid) {
 67	        return i;
 68	      }
 69	    }
 70	  } else {
 71	    for (let i: number = activeStop + 1; i < activeTour.stops.length; ++i) {
 72	      if (activeTour.stops[i].isValid) {
 73	        return i;
 74	      }
 75	    }
 76	  }
 77	
 78	  return undefined;
 79	}
 80	
 81	class TourStopComponent extends React.PureComponent<TourStopProps> {
 82	  tourStopInfo: TourStopInfo[];
 83	
 84	  constructor(props: TourStopProps) {
 85	    super(props);
 86	
 87	    this.tourStopInfo = Array.isArray(props.info) ? props.info : [props.info];
 88	  }
 89	
 90	  private getStop = (direction: 'back' | 'forward'): number | undefined => {
 91	    if (this.props.activeStop === undefined) {
 92	      return undefined;
 93	    }
 94	
 95	    return getNextTourStop(this.props.activeTour!, this.props.activeStop!, direction);
 96	  };
 97	
 98	  private setStop = (stop: number): void => {
 99	    this.props.setStop(stop);
100	  };
101	
102	  private backButton = (): React.ReactNode => {
103	    const stop = this.getStop('back');
104	
105	    return (
106	      <Button isDisabled={stop === undefined} variant={ButtonVariant.secondary} onClick={() => this.setStop(stop!)}>
107	        <KialiIcon.AngleLeft /> {t('Back')}
108	      </Button>
109	    );
110	  };
111	
112	  private nextButton = (): React.ReactNode => {
113	    const stop = this.getStop('forward');
114	
115	    if (stop === undefined) {
116	      return (
117	        <Button variant={ButtonVariant.primary} onClick={this.props.endTour}>
118	          {t('Done')}
119	        </Button>
120	      );
121	    }
122	
123	    return (
124	      <Button variant={ButtonVariant.primary} onClick={() => this.setStop(stop!)}>
125	        {t('Next')} <KialiIcon.AngleRight />
126	      </Button>
127	    );
128	  };
129	
130	  private activeInfo = (): TourStopInfo | undefined => {
131	    for (const tsi of this.tourStopInfo) {
132	      const name = tsi.name;
133	      const isActive =
134	        this.props.activeTour !== undefined && name === this.props.activeTour.stops[this.props.activeStop!].name;
135	
136	      if (isActive) {
137	        return tsi;
138	      }
139	    }
140	
141	    return undefined;
142	  };
143	
144	  // This is here to workaround what seems to be a bug.  As far as I know when isVisible is set then outside clicks should not hide
145	  // the Popover, but it seems to be happening in certain scenarios. So, if the Popover is still valid, unhide it immediately.
146	  private onHidden = (): void => {
147	    if (this.activeInfo()) {
148	      this.forceUpdate();
149	    }
150	  };
151	
152	  private onResize = (): void => {
153	    if (this.activeInfo()) {
154	      this.forceUpdate();
155	    }
156	  };
157	
158	  private shouldClose = (): void => {
159	    this.props.endTour();
160	  };
161	
162	  componentDidMount(): void {
163	    this.tourStopInfo.forEach(ti => (ti.isValid = true));
164	  }
165	
166	  componentWillUnmount(): void {
167	    this.tourStopInfo.forEach(ti => (ti.isValid = false));
168	  }
169	
170	  render(): React.ReactNode {
171	    const info = this.activeInfo();
172	    const offset = info && info.distance ? info.distance : 25;
173	    const children = this.props.children;
174	
175	    return (
176	      <>
177	        {info ? (
178	          <>
179	            <ReactResizeDetector
180	              refreshMode={'debounce'}
181	              refreshRate={100}
182	              skipOnMount={true}
183	              handleWidth={true}
184	              handleHeight={true}
185	              onResize={this.onResize}
186	            />
187	            <Popover
188	              bodyContent={info.description ? t(info.description) : info.htmlDescription}
189	              distance={offset}
190	              footerContent={
191	                <div className={buttonsStyle}>
192	                  {this.backButton()}
193	                  {this.nextButton()}
194	                </div>
195	              }
196	              headerContent={
197	                <div>
198	                  <span className={stopNumberStyle}>{this.props.activeStop! + 1}</span>
199	                  <span>{t(info.name)}</span>
200	                </div>
201	              }
202	              isVisible={true}
203	              onHidden={this.onHidden}
204	              position={info.position}
205	              shouldClose={(_event, _) => this.shouldClose()}
206	            >
207	              <>{children}</>
208	            </Popover>
209	          </>
210	        ) : (
211	          <>{children}</>
212	        )}
213	      </>
214	    );
215	  }
216	}
217	
218	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
219	  activeTour: state.tourState.activeTour,
220	  activeStop: state.tourState.activeStop
221	});
222	
223	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
224	  return {
225	    endTour: bindActionCreators(TourActions.endTour, dispatch),
226	    setStop: bindActionCreators(TourActions.setStop, dispatch)
227	  };
228	};
229	
230	export const TourStop = connect(mapStateToProps, mapDispatchToProps)(TourStopComponent);

