 59	export function getNextTourStop(
 60	  activeTour: TourInfo,
 61	  activeStop: number,
 62	  direction: 'back' | 'forward'
 63	): number | undefined {
 64	  if (direction === 'back') {
 65	    for (let i: number = activeStop - 1; i >= 0; --i) {
 66	      if (activeTour.stops[i].isValid) {
 67	        return i;
 68	      }
 69	    }
 70	  } else {
 71	    for (let i: number = activeStop + 1; i < activeTour.stops.length; ++i) {
 72	      if (activeTour.stops[i].isValid) {
 73	        return i;
 74	      }
 75	    }
 76	  }
 77	
 78	  return undefined;
 79	}
